# {Use an approach that evaluates potential energy by considering gravitational analogy in route selection, whereby nodes exert an 'attraction' based on time window constraints as well as their remaining time-to-window and distance from the current position.}

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    max_attraction = float('-inf')
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        distance = euclidean_distance(cur_truck_pos, customer_pos)
        arrival_time = current_time + (distance / truck_speed)

        start_time, end_time = time_windows[i]
        remaining_time_to_window = max(0, start_time - arrival_time)
        window_duration = end_time - start_time

        if arrival_time > end_time:
            attraction = float('-inf')  # Avoid nodes with expired time windows
        else:
            time_factor = 1.0 / (1 + remaining_time_to_window)
            distance_factor = 1.0 / (1 + distance)
            window_factor = 1.0 / (window_duration + 1)

            attraction = time_factor * 0.5 + distance_factor * 0.3 + window_factor * 0.2

        if attraction > max_attraction:
            max_attraction = attraction
            best_node = i

    return best_node
